import zeep

# Create a new instance of the client
client = zeep.Client('http://localhost:8080/insurance?wsdl')

def get_policy_details(policy_number, customer_name):
    # Create a SOAP request with user-provided values inserted directly into the XML body
    policy_request = {
        'policyNumber': policy_number,
        'customerName': customer_name
    }

    try:
        response = client.service.getPolicyDetails(**policy_request)
        return response
    except Exception as e:
        print(f"Error: {e}")

def main():
    # Accept user input for policy lookup
    policy_number = input("Enter policy number: ")
    customer_name = input("Enter customer name: ")

    # Send the request to the third-party insurance service
    result = get_policy_details(policy_number, customer_name)

    if result:
        print(result)
    else:
        print("No policy details found.")

if __name__ == "__main__":
    main()